import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import Navbar from "@/components/feature/Navbar";
import FooterSection from "@/pages/home/components/FooterSection";
import { blogPosts, blogCategories } from "@/mocks/blog";

export default function BlogPage() {
  useEffect(() => { window.scrollTo(0, 0); }, []);
  const [activeCategory, setActiveCategory] = useState("All");

  const filtered = activeCategory === "All"
    ? blogPosts
    : blogPosts.filter((p) => p.category === activeCategory);

  const [hero, ...rest] = filtered;

  return (
    <div className="min-h-screen bg-white">
      <div className="fixed top-0 left-0 right-0 z-50">
        <Navbar />
      </div>

      <div style={{ paddingTop: 64 }}>
        {/* Dark header */}
        <div style={{ background: "#111111" }} className="py-16 px-8">
          <div className="max-w-[1320px] mx-auto">
            <p className="text-[11px] font-bold uppercase tracking-[0.3em] text-white/30 mb-3">Valkyrie Peptides</p>
            <h1
              className="font-black uppercase leading-[0.88] tracking-tight"
              style={{ fontFamily: "'Oswald', sans-serif", fontSize: "clamp(32px, 4.5vw, 64px)", background: "linear-gradient(135deg, #888 0%, #c0c0c0 30%, #606060 55%, #aaa 75%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}
            >
              RESEARCH &amp;<br />
              <span style={{ background: "linear-gradient(135deg, #707070 0%, #b0b0b0 30%, #484848 55%, #999 75%, #606060 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", fontFamily: "'Oswald', sans-serif", fontWeight: 700 }}>
                NEWS
              </span>
            </h1>
            <p className="text-white/45 text-sm mt-4 max-w-xl leading-relaxed">
              Science-backed articles on peptide research, lab best practices, quality standards, and the latest in research-grade compounds.
            </p>
          </div>
        </div>

        {/* Breadcrumb */}
        <div style={{ background: "#ffffff", borderBottom: "1px solid #e8e8e8" }} className="px-8 py-3">
          <div className="max-w-[1320px] mx-auto flex items-center gap-2 text-xs text-[#aaa]">
            <Link to="/" className="hover:text-[#111] transition-colors cursor-pointer">Home</Link>
            <i className="ri-arrow-right-s-line"></i>
            <span className="text-[#111]">Blog</span>
          </div>
        </div>

        {/* Category filter */}
        <div className="sticky z-20 w-full border-b border-[#ebebeb] bg-white" style={{ top: 64 }}>
          <div className="max-w-[1320px] mx-auto px-8 py-3 flex flex-wrap items-center gap-2">
            {blogCategories.map((cat) => (
              <button
                key={cat}
                onClick={() => setActiveCategory(cat)}
                className="px-4 py-2 text-[11px] font-bold uppercase tracking-wider cursor-pointer whitespace-nowrap transition-all duration-150"
                style={{
                  background: activeCategory === cat ? "#111111" : "#f5f4f2",
                  color: activeCategory === cat ? "#ffffff" : "#888888",
                }}
              >
                {cat}
              </button>
            ))}
            <span className="ml-auto text-[#aaa] text-xs font-semibold uppercase tracking-wider whitespace-nowrap">
              {filtered.length} article{filtered.length !== 1 ? "s" : ""}
            </span>
          </div>
        </div>

        <div className="py-12 px-8" style={{ background: "#f8f7f5" }}>
          <div className="max-w-[1320px] mx-auto">

            {filtered.length === 0 ? (
              <div className="text-center py-20">
                <p className="text-[#aaa] text-sm font-semibold uppercase tracking-widest">No articles in this category</p>
              </div>
            ) : (
              <>
                {/* Hero post */}
                {hero && (
                  <Link
                    to={`/blog/${hero.slug}`}
                    className="group grid grid-cols-1 lg:grid-cols-2 gap-px mb-px cursor-pointer"
                    style={{ background: "#e0e0e0" }}
                  >
                    <div className="relative overflow-hidden bg-white" style={{ minHeight: 380 }}>
                      <img
                        src={hero.image}
                        alt={hero.title}
                        className="w-full h-full object-cover object-top absolute inset-0 transition-transform duration-700 group-hover:scale-[1.03]"
                      />
                      <div className="absolute top-5 left-5">
                        <span className="text-[9px] font-black uppercase tracking-widest px-3 py-1.5" style={{ background: "#111", color: "#fff" }}>
                          {hero.category}
                        </span>
                      </div>
                    </div>
                    <div className="bg-white p-10 lg:p-14 flex flex-col justify-center">
                      <div className="flex items-center gap-3 mb-5">
                        <span className="text-[#aaa] text-[10px] uppercase tracking-widest">{hero.date}</span>
                        <span className="text-[#ddd]">·</span>
                        <span className="text-[#aaa] text-[10px] uppercase tracking-widest">{hero.readTime}</span>
                      </div>
                      <h2
                        className="font-black uppercase leading-tight tracking-tight mb-4"
                        style={{ fontFamily: "'Oswald', sans-serif", fontSize: "clamp(22px, 2.5vw, 36px)", background: "linear-gradient(135deg, #888 0%, #c0c0c0 35%, #666 60%, #aaa 80%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}
                      >
                        {hero.title}
                      </h2>
                      <p className="text-[#777] text-sm leading-relaxed mb-8">{hero.excerpt}</p>
                      <div className="flex flex-wrap gap-2 mb-8">
                        {hero.tags.map((tag) => (
                          <span key={tag} className="text-[9px] font-bold uppercase tracking-widest px-2.5 py-1" style={{ background: "#f5f4f2", color: "#888", border: "1px solid #e0e0e0" }}>
                            {tag}
                          </span>
                        ))}
                      </div>
                      <div className="inline-flex items-center gap-2">
                        <span className="text-[11px] font-black uppercase tracking-widest text-[#111]">Read Article</span>
                        <div className="w-4 h-4 flex items-center justify-center">
                          <i className="ri-arrow-right-line text-xs"></i>
                        </div>
                      </div>
                    </div>
                  </Link>
                )}

                {/* Rest of posts grid */}
                {rest.length > 0 && (
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-px mt-px" style={{ background: "#e0e0e0" }}>
                    {rest.map((post) => (
                      <Link
                        key={post.slug}
                        to={`/blog/${post.slug}`}
                        className="group flex flex-col bg-white cursor-pointer"
                      >
                        <div className="relative overflow-hidden" style={{ height: 220 }}>
                          <img
                            src={post.image}
                            alt={post.title}
                            className="w-full h-full object-cover object-top transition-transform duration-700 group-hover:scale-[1.04]"
                          />
                          <div className="absolute top-3 left-3">
                            <span className="text-[9px] font-black uppercase tracking-widest px-2.5 py-1" style={{ background: "#111", color: "#fff" }}>
                              {post.category}
                            </span>
                          </div>
                        </div>
                        <div className="p-7 flex flex-col flex-1">
                          <div className="flex items-center gap-2 mb-3">
                            <span className="text-[#aaa] text-[10px] uppercase tracking-widest">{post.date}</span>
                            <span className="text-[#ddd]">·</span>
                            <span className="text-[#aaa] text-[10px] uppercase tracking-widest">{post.readTime}</span>
                          </div>
                          <h3
                            className="font-black uppercase leading-tight tracking-tight mb-3 flex-1"
                            style={{ fontFamily: "'Oswald', sans-serif", fontSize: 16, background: "linear-gradient(135deg, #888 0%, #c0c0c0 35%, #666 60%, #aaa 80%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}
                          >
                            {post.title}
                          </h3>
                          <p className="text-[#888] text-xs leading-relaxed mb-5 line-clamp-2">{post.excerpt}</p>
                          <div className="flex flex-wrap gap-1.5 mb-5">
                            {post.tags.slice(0, 3).map((tag) => (
                              <span key={tag} className="text-[9px] font-bold uppercase tracking-widest px-2 py-0.5" style={{ background: "#f5f4f2", color: "#999", border: "1px solid #e8e8e8" }}>
                                {tag}
                              </span>
                            ))}
                          </div>
                          <div className="flex items-center gap-1.5 mt-auto">
                            <span className="text-[10px] font-black uppercase tracking-widest text-[#aaa] group-hover:text-[#111] transition-colors">Read Article</span>
                            <div className="w-3.5 h-3.5 flex items-center justify-center">
                              <i className="ri-arrow-right-line text-[10px] text-[#aaa] group-hover:text-[#111] transition-colors"></i>
                            </div>
                          </div>
                        </div>
                      </Link>
                    ))}
                  </div>
                )}
              </>
            )}
          </div>
        </div>

        <FooterSection />
      </div>
    </div>
  );
}
