import { useState, useMemo } from "react";
import { Link } from "react-router-dom";
import Navbar from "@/components/feature/Navbar";
import FooterSection from "@/pages/home/components/FooterSection";
import { useCart } from "@/hooks/useCart";
import { useProducts } from "@/hooks/useProducts";
import WaitlistModal from "@/components/feature/WaitlistModal";
import type { NormalizedProduct } from "@/lib/woocommerce";

type SortOption = "default" | "price-asc" | "price-desc" | "name-asc";

const SORT_LABELS: Record<SortOption, string> = {
  default: "Default Sorting",
  "price-asc": "Price: Low to High",
  "price-desc": "Price: High to Low",
  "name-asc": "Name: A–Z",
};

export default function ShopPage() {
  const [sort, setSort] = useState<SortOption>("default");
  const [filter, setFilter] = useState<"all" | "in-stock" | "out-of-stock">("all");
  const [added, setAdded] = useState<number | null>(null);
  const [sortOpen, setSortOpen] = useState(false);
  const [waitlistProduct, setWaitlistProduct] = useState<string | null>(null);
  const { addItem } = useCart();
  const { products, loading, error, refetch } = useProducts();

  const handleAdd = (product: NormalizedProduct) => {
    if (!product.inStock) return;
    addItem({ id: product.id, slug: product.slug, name: product.name, price: product.price, image: product.image });
    setAdded(product.id);
    setTimeout(() => setAdded(null), 2000);
  };

  const inStockCount = products.filter((p) => p.inStock).length;
  const outOfStockCount = products.filter((p) => !p.inStock).length;

  const filtered = useMemo(() => {
    let list = [...products];
    if (filter === "in-stock") list = list.filter((p) => p.inStock);
    if (filter === "out-of-stock") list = list.filter((p) => !p.inStock);
    if (sort === "price-asc") list.sort((a, b) => a.price - b.price);
    if (sort === "price-desc") list.sort((a, b) => b.price - a.price);
    if (sort === "name-asc") list.sort((a, b) => a.name.localeCompare(b.name));
    return list;
  }, [sort, filter, products]);

  return (
    <div className="min-h-screen bg-white">
      <div className="fixed top-0 left-0 right-0 z-50">
        <Navbar />
      </div>
      <main style={{ paddingTop: 64 }}>

        {/* Page header */}
        <div className="w-full py-16 px-8" style={{ background: "#111111" }}>
          <div className="max-w-[1320px] mx-auto">
            <p className="text-[11px] font-bold uppercase tracking-[0.3em] text-white/40 mb-3">
              Valkyrie Peptides
            </p>
            <h1 className="font-black uppercase tracking-tight leading-none" style={{ fontSize: "clamp(36px, 5vw, 72px)", background: "linear-gradient(135deg, #888 0%, #c0c0c0 30%, #606060 55%, #aaa 75%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}>
              SHOP ALL<br />
              <span style={{ background: "linear-gradient(135deg, #707070 0%, #b0b0b0 30%, #484848 55%, #999 75%, #606060 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", fontFamily: "'Oswald', sans-serif", fontWeight: 700 }}>
                PEPTIDES
              </span>
            </h1>
            <p className="text-white/45 text-sm mt-5 max-w-lg leading-relaxed">
              Research-grade peptides lyophilized and verified in the USA. Every product 3rd-party tested for purity, identity, and composition.
            </p>
          </div>
        </div>

        {/* Toolbar */}
        <div className="sticky top-[64px] z-20 w-full border-b border-[#ebebeb] bg-white">
          <div className="max-w-[1320px] mx-auto px-8 flex flex-wrap items-center justify-between gap-4 py-4">
            <div className="flex items-center gap-1" style={{ background: "#f5f4f2", padding: "4px", borderRadius: 4 }}>
              {(["all", "in-stock", "out-of-stock"] as const).map((f) => (
                <button
                  key={f}
                  onClick={() => setFilter(f)}
                  className="px-4 py-1.5 text-[11px] font-bold uppercase tracking-wider cursor-pointer whitespace-nowrap transition-all duration-150"
                  style={{
                    background: filter === f ? "#111111" : "transparent",
                    color: filter === f ? "#ffffff" : "#888888",
                    borderRadius: 2,
                  }}
                >
                  {f === "all" ? `All (${products.length})` : f === "in-stock" ? `In Stock (${inStockCount})` : `Out of Stock (${outOfStockCount})`}
                </button>
              ))}
            </div>
            <div className="flex items-center gap-4">
              {loading && (
                <span className="text-[#bbb] text-xs font-semibold uppercase tracking-wider flex items-center gap-2">
                  <span className="inline-block w-3 h-3 border-2 border-[#bbb] border-t-transparent rounded-full animate-spin" />
                  Loading…
                </span>
              )}
              {error && (
                <button onClick={refetch} className="text-red-500 text-xs font-bold uppercase tracking-wider cursor-pointer hover:text-red-700">
                  ⚠ Retry
                </button>
              )}
              {!loading && (
                <span className="text-[#aaa] text-xs font-semibold uppercase tracking-wider">
                  {filtered.length} product{filtered.length !== 1 ? "s" : ""}
                </span>
              )}
              <div className="relative">
                <button
                  onClick={() => setSortOpen(!sortOpen)}
                  className="flex items-center gap-2 text-[11px] font-bold uppercase tracking-wider px-4 py-2 cursor-pointer whitespace-nowrap transition-colors"
                  style={{ border: "1px solid #e0e0e0", color: "#333" }}
                >
                  {SORT_LABELS[sort]}
                  <div className="w-3 h-3 flex items-center justify-center">
                    {sortOpen ? <i className="ri-arrow-up-s-line text-xs"></i> : <i className="ri-arrow-down-s-line text-xs"></i>}
                  </div>
                </button>
                {sortOpen && (
                  <div className="absolute right-0 top-full mt-1 w-52 bg-white z-30" style={{ border: "1px solid #e0e0e0" }}>
                    {(Object.keys(SORT_LABELS) as SortOption[]).map((key) => (
                      <button
                        key={key}
                        onClick={() => { setSort(key); setSortOpen(false); }}
                        className="w-full text-left px-4 py-3 text-[11px] font-bold uppercase tracking-wider cursor-pointer transition-colors hover:bg-[#f5f4f2] whitespace-nowrap"
                        style={{ color: sort === key ? "#111" : "#666", background: sort === key ? "#f5f4f2" : "transparent" }}
                      >
                        {SORT_LABELS[key]}
                      </button>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Loading skeleton */}
        {loading && (
          <div className="max-w-[1320px] mx-auto px-8 py-12">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-px" style={{ background: "#e0e0e0" }}>
              {Array.from({ length: 8 }).map((_, i) => (
                <div key={i} className="bg-white p-6 animate-pulse">
                  <div className="bg-[#f0ede8] h-[300px] mb-6" />
                  <div className="h-3 bg-[#eee] rounded mb-2 w-1/3" />
                  <div className="h-4 bg-[#eee] rounded mb-4 w-3/4" />
                  <div className="h-6 bg-[#eee] rounded mb-6 w-1/2" />
                  <div className="h-12 bg-[#eee] rounded" />
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Error state */}
        {error && !loading && (
          <div className="max-w-[1320px] mx-auto px-8 py-24 text-center">
            <p className="text-red-500 font-bold uppercase tracking-widest text-sm mb-4">Failed to load products</p>
            <p className="text-[#888] text-xs mb-8 max-w-md mx-auto">{error}</p>
            <button
              onClick={refetch}
              className="font-black uppercase tracking-widest text-[11px] px-8 py-4 cursor-pointer"
              style={{ background: "#111", color: "#fff" }}
            >
              Try Again
            </button>
          </div>
        )}

        {/* Product grid */}
        {!loading && !error && (
          <div className="max-w-[1320px] mx-auto px-8 py-12">
            <div
              className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-px"
              style={{ background: "#e0e0e0" }}
              data-product-shop
            >
              {filtered.map((product) => (
                <div
                  key={product.id}
                  className="group flex flex-col bg-white transition-all duration-300"
                  onMouseEnter={(e) => { (e.currentTarget as HTMLDivElement).style.background = "#fafafa"; }}
                  onMouseLeave={(e) => { (e.currentTarget as HTMLDivElement).style.background = "#ffffff"; }}
                >
                  <Link
                    to={`/products/${product.slug}`}
                    className="relative overflow-hidden block cursor-pointer"
                    style={{ background: "#f0ede8", height: 300 }}
                  >
                    {!product.inStock && (
                      <div className="absolute inset-0 z-10 flex items-center justify-center" style={{ background: "rgba(255,255,255,0.65)" }}>
                        <span className="text-[9px] font-black uppercase tracking-widest px-3 py-1.5" style={{ background: "#111111", color: "#ffffff" }}>
                          Out of Stock
                        </span>
                      </div>
                    )}
                    <img
                      src={product.image}
                      alt={product.name}
                      className="w-full h-full object-contain object-center group-hover:scale-105 transition-transform duration-700 p-6"
                      style={{ mixBlendMode: "multiply" }}
                    />
                  </Link>

                  <div className="flex flex-col flex-1 p-6" style={{ borderTop: "1px solid #ebebeb" }}>
                    <Link to={`/products/${product.slug}`} className="block mb-3 cursor-pointer">
                      <p className="text-[#bbb] text-[9px] uppercase tracking-[0.25em] mb-2">{product.category}</p>
                      <h3 className="text-[#111111] font-black text-sm leading-snug uppercase tracking-tight hover:text-[#555] transition-colors">{product.name}</h3>
                    </Link>

                    <div className="flex items-center gap-1.5 mb-5">
                      <div className="w-3 h-3 flex items-center justify-center">
                        <i className="ri-shield-check-fill text-green-600 text-xs"></i>
                      </div>
                      <span className="text-[10px] text-green-700 font-semibold">99%+ Purity Verified</span>
                    </div>

                    <div className="flex items-center justify-between mb-5">
                      <span className="text-[#111111] font-black text-2xl">${product.price.toFixed(2)}</span>
                      <span className="text-[#aaa] text-[10px] uppercase tracking-widest">USD</span>
                    </div>

                    {product.inStock ? (
                      <button
                        onClick={() => handleAdd(product)}
                        className="w-full font-black uppercase tracking-widest text-[11px] py-4 transition-all duration-200 cursor-pointer whitespace-nowrap"
                        style={{
                          background: added === product.id ? "#16a34a" : "#111111",
                          color: "#ffffff",
                        }}
                      >
                        {added === product.id ? "✓ Added to Cart" : "Add to Cart"}
                      </button>
                    ) : (
                      <button
                        onClick={() => setWaitlistProduct(product.name)}
                        className="w-full font-black uppercase tracking-widest text-[11px] py-4 transition-all duration-200 cursor-pointer whitespace-nowrap flex items-center justify-center gap-2"
                        style={{ background: "#f5f4f2", color: "#111", border: "1px solid #e0e0e0" }}
                      >
                        <div className="w-4 h-4 flex items-center justify-center">
                          <i className="ri-notification-3-line text-xs"></i>
                        </div>
                        Notify Me When Back
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>

            {filtered.length === 0 && !loading && (
              <div className="text-center py-24">
                <p className="text-[#aaa] text-sm font-semibold uppercase tracking-widest">No products found</p>
              </div>
            )}
          </div>
        )}

        {/* Bottom trust strip */}
        <div className="w-full border-t border-[#ebebeb] mt-4">
          <div className="max-w-[1320px] mx-auto px-8">
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-px" style={{ background: "#e8e8e8" }}>
              {[
                { icon: "ri-shield-check-line", label: "3rd Party Lab Tested", color: "#16a34a" },
                { icon: "ri-truck-line", label: "Ships 1–2 Business Days", color: "#111" },
                { icon: "ri-map-pin-line", label: "Made in the USA", color: "#111" },
                { icon: "ri-lock-2-line", label: "Secure Checkout", color: "#111" },
              ].map((item) => (
                <div key={item.label} className="flex items-center justify-center gap-3 py-5 bg-white">
                  <div className="w-5 h-5 flex items-center justify-center">
                    <i className={`${item.icon} text-base`} style={{ color: item.color }}></i>
                  </div>
                  <span className="text-[#444] text-xs font-bold uppercase tracking-wide whitespace-nowrap">{item.label}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </main>

      {waitlistProduct && (
        <WaitlistModal
          productName={waitlistProduct}
          onClose={() => setWaitlistProduct(null)}
        />
      )}
      <FooterSection />
    </div>
  );
}
