import { useEffect } from "react";
import { Link, useParams, useNavigate } from "react-router-dom";
import Navbar from "@/components/feature/Navbar";
import FooterSection from "@/pages/home/components/FooterSection";
import { blogPosts } from "@/mocks/blog";

export default function BlogPostPage() {
  const { slug } = useParams<{ slug: string }>();
  const navigate = useNavigate();
  const post = blogPosts.find((p) => p.slug === slug);
  const related = blogPosts.filter((p) => p.slug !== slug).slice(0, 3);

  useEffect(() => {
    window.scrollTo(0, 0);
    if (!post) navigate("/blog", { replace: true });
  }, [slug, post, navigate]);

  if (!post) return null;

  // Convert markdown-ish body to paragraphs/headings
  const renderBody = (body: string) => {
    const lines = body.split("\n");
    const elements: JSX.Element[] = [];
    let key = 0;

    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      if (trimmed.startsWith("## ")) {
        elements.push(
          <h2
            key={key++}
            className="font-black uppercase tracking-tight mt-10 mb-4"
            style={{ fontFamily: "'Oswald', sans-serif", fontSize: "clamp(18px, 2vw, 24px)", background: "linear-gradient(135deg, #888 0%, #c0c0c0 35%, #666 60%, #aaa 80%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}
          >
            {trimmed.replace("## ", "")}
          </h2>
        );
      } else {
        // Handle inline bold (**text**)
        const parts = trimmed.split(/(\*\*[^*]+\*\*)/g);
        elements.push(
          <p key={key++} className="text-[#555] text-base leading-[1.85] mb-4">
            {parts.map((part, i) =>
              part.startsWith("**") && part.endsWith("**")
                ? <strong key={i} className="text-[#111] font-bold">{part.slice(2, -2)}</strong>
                : part
            )}
          </p>
        );
      }
    }
    return elements;
  };

  return (
    <div className="min-h-screen bg-white">
      <div className="fixed top-0 left-0 right-0 z-50">
        <Navbar />
      </div>

      <div style={{ paddingTop: 64 }}>
        {/* Hero image */}
        <div className="relative w-full overflow-hidden" style={{ height: 480, background: "#111" }}>
          <img
            src={post.image}
            alt={post.title}
            className="absolute inset-0 w-full h-full object-cover object-top"
            style={{ opacity: 0.75 }}
          />
          <div className="absolute inset-0" style={{ background: "linear-gradient(to top, rgba(0,0,0,0.85) 0%, rgba(0,0,0,0.3) 60%, transparent 100%)" }} />
          <div className="absolute bottom-0 left-0 right-0 px-8 pb-12">
            <div className="max-w-[860px] mx-auto">
              <span className="inline-block text-[9px] font-black uppercase tracking-widest px-3 py-1.5 mb-5" style={{ background: "#fff", color: "#111" }}>
                {post.category}
              </span>
              <h1
                className="font-black uppercase leading-tight tracking-tight"
                style={{ fontFamily: "'Oswald', sans-serif", fontSize: "clamp(26px, 4vw, 52px)", background: "linear-gradient(135deg, #c8c8c8 0%, #f0f0f0 30%, #a0a0a0 55%, #d8d8d8 75%, #b0b0b0 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}
              >
                {post.title}
              </h1>
            </div>
          </div>
        </div>

        {/* Breadcrumb + meta */}
        <div style={{ background: "#ffffff", borderBottom: "1px solid #e8e8e8" }} className="px-8 py-3">
          <div className="max-w-[860px] mx-auto flex items-center justify-between flex-wrap gap-3">
            <div className="flex items-center gap-2 text-xs text-[#aaa]">
              <Link to="/" className="hover:text-[#111] transition-colors cursor-pointer">Home</Link>
              <i className="ri-arrow-right-s-line"></i>
              <Link to="/blog" className="hover:text-[#111] transition-colors cursor-pointer">Blog</Link>
              <i className="ri-arrow-right-s-line"></i>
              <span className="text-[#111] truncate max-w-[200px]">{post.title}</span>
            </div>
            <div className="flex items-center gap-4 text-[10px] text-[#aaa] uppercase tracking-widest">
              <span>{post.date}</span>
              <span className="text-[#ddd]">·</span>
              <span>{post.readTime}</span>
              <span className="text-[#ddd]">·</span>
              <span>{post.author}</span>
            </div>
          </div>
        </div>

        {/* Article body */}
        <div className="py-14 px-8">
          <div className="max-w-[860px] mx-auto">

            {/* Excerpt / lead */}
            <p
              className="text-[#333] text-lg leading-relaxed mb-10 font-medium"
              style={{ borderLeft: "3px solid #111", paddingLeft: 20 }}
            >
              {post.excerpt}
            </p>

            {/* Body */}
            <div>{renderBody(post.body)}</div>

            {/* Tags */}
            <div className="flex flex-wrap gap-2 mt-12 pt-8" style={{ borderTop: "1px solid #ebebeb" }}>
              <span className="text-[10px] font-black uppercase tracking-widest text-[#aaa] mr-2 self-center">Tags:</span>
              {post.tags.map((tag) => (
                <span key={tag} className="text-[10px] font-bold uppercase tracking-widest px-3 py-1.5" style={{ background: "#f5f4f2", color: "#666", border: "1px solid #e0e0e0" }}>
                  {tag}
                </span>
              ))}
            </div>

            {/* Author */}
            <div className="flex items-center gap-5 mt-10 p-6" style={{ background: "#f8f7f5", border: "1px solid #ebebeb" }}>
              <div className="w-12 h-12 flex items-center justify-center flex-shrink-0" style={{ background: "#111" }}>
                <i className="ri-microscope-line text-white text-xl"></i>
              </div>
              <div>
                <p className="font-black text-sm uppercase tracking-tight text-[#111]">{post.author}</p>
                <p className="text-[#888] text-xs mt-0.5">{post.authorRole} · Valkyrie Peptides</p>
              </div>
            </div>

            {/* Disclaimer */}
            <div className="mt-8 p-5" style={{ background: "#fffbf0", border: "1px solid #f0e8c8" }}>
              <p className="text-[#888] text-xs leading-relaxed">
                <strong className="text-[#666]">Research Use Only.</strong> All content on this page is intended for educational and informational purposes only. Products referenced are for research use only and are not intended for human consumption, injection, or therapeutic use.
              </p>
            </div>
          </div>
        </div>

        {/* Related posts */}
        <div className="px-8 pb-16" style={{ background: "#f8f7f5", borderTop: "1px solid #ebebeb" }}>
          <div className="max-w-[1320px] mx-auto pt-12">
            <div className="flex items-center justify-between mb-8">
              <h3
                className="font-black uppercase tracking-tight"
                style={{ fontFamily: "'Oswald', sans-serif", fontSize: "clamp(20px, 2vw, 28px)", background: "linear-gradient(135deg, #888 0%, #c0c0c0 35%, #666 60%, #aaa 80%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}
              >
                More Articles
              </h3>
              <Link
                to="/blog"
                className="text-[11px] font-black uppercase tracking-widest text-[#aaa] hover:text-[#111] transition-colors cursor-pointer"
              >
                View All
              </Link>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-px" style={{ background: "#e0e0e0" }}>
              {related.map((p) => (
                <Link
                  key={p.slug}
                  to={`/blog/${p.slug}`}
                  className="group flex flex-col bg-white cursor-pointer"
                >
                  <div className="relative overflow-hidden" style={{ height: 180 }}>
                    <img
                      src={p.image}
                      alt={p.title}
                      className="w-full h-full object-cover object-top transition-transform duration-700 group-hover:scale-[1.04]"
                    />
                    <div className="absolute top-3 left-3">
                      <span className="text-[9px] font-black uppercase tracking-widest px-2.5 py-1" style={{ background: "#111", color: "#fff" }}>
                        {p.category}
                      </span>
                    </div>
                  </div>
                  <div className="p-6 flex flex-col flex-1">
                    <span className="text-[#aaa] text-[10px] uppercase tracking-widest mb-2">{p.date}</span>
                    <h4
                      className="font-black uppercase leading-tight tracking-tight text-[#111] text-sm group-hover:text-[#444] transition-colors flex-1"
                      style={{ fontFamily: "'Oswald', sans-serif" }}
                    >
                      {p.title}
                    </h4>
                    <div className="flex items-center gap-1.5 mt-4">
                      <span className="text-[10px] font-black uppercase tracking-widest text-[#aaa] group-hover:text-[#111] transition-colors">Read</span>
                      <div className="w-3.5 h-3.5 flex items-center justify-center">
                        <i className="ri-arrow-right-line text-[10px] text-[#aaa] group-hover:text-[#111] transition-colors"></i>
                      </div>
                    </div>
                  </div>
                </Link>
              ))}
            </div>
          </div>
        </div>

        <FooterSection />
      </div>
    </div>
  );
}
