import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import Navbar from "@/components/feature/Navbar";
import FooterSection from "@/pages/home/components/FooterSection";
import { useCart } from "@/hooks/useCart";
import { createOrder, type WCOrderPayload } from "@/lib/woocommerce";

type PaymentMethod = "zelle" | "cashapp" | "venmo";

const ZELLE_INFO   = { phone: "(208) 243-9222", name: "Valkyrie Research LLC" };
const CASHAPP_INFO = { tag: "$ValkyrieResearch" };
const VENMO_INFO   = { tag: "@ValkyrieResearch" };

const METHOD_LABELS: Record<PaymentMethod, string> = {
  zelle:   "Zelle",
  cashapp: "Cash App",
  venmo:   "Venmo",
};

export default function OrderPage() {
  const { items, totalPrice, clearCart } = useCart();
  const navigate = useNavigate();

  const [method, setMethod]               = useState<PaymentMethod>("zelle");
  const [step, setStep]                   = useState<1 | 2 | 3>(1);
  const [submitting, setSubmitting]       = useState(false);
  const [submitError, setSubmitError]     = useState<string | null>(null);
  const [submitted, setSubmitted]         = useState(false);
  const [orderId, setOrderId]             = useState<string | null>(null);
  const [paymentConfirmed, setPaymentConfirmed] = useState(false);

  const [form, setForm] = useState({
    firstName: "",
    lastName: "",
    email: "",
    phone: "",
    address: "",
    city: "",
    state: "",
    zip: "",
    notes: "",
  });

  useEffect(() => { window.scrollTo(0, 0); }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setForm((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  // ─── Submit → create real WC order ───────────────────────────────────────
  const handleSubmitOrder = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!paymentConfirmed || submitting) return;

    setSubmitting(true);
    setSubmitError(null);

    const methodTitle =
      method === "zelle"   ? `Zelle (${ZELLE_INFO.phone})`
      : method === "cashapp" ? `Cash App (${CASHAPP_INFO.tag})`
      :                        `Venmo (${VENMO_INFO.tag})`;

    const payload: WCOrderPayload = {
      payment_method:       method,
      payment_method_title: methodTitle,
      set_paid:             false,
      status:               "pending",
      billing: {
        first_name: form.firstName,
        last_name:  form.lastName,
        email:      form.email,
        phone:      form.phone,
        address_1:  form.address,
        city:       form.city,
        state:      form.state,
        postcode:   form.zip,
        country:    "US",
      },
      shipping: {
        first_name: form.firstName,
        last_name:  form.lastName,
        address_1:  form.address,
        city:       form.city,
        state:      form.state,
        postcode:   form.zip,
        country:    "US",
      },
      line_items: items.map((item) => ({
        product_id: item.id,
        quantity:   item.quantity,
        name:       item.name,
      })),
      customer_note: form.notes || undefined,
      meta_data: [
        { key: "_payment_sent_confirmed", value: "yes" },
        { key: "_payment_method_detail",  value: methodTitle },
        { key: "_customer_phone",         value: form.phone },
      ],
    };

    try {
      const order = await createOrder(payload);
      setOrderId(order.number ?? String(order.id));
      clearCart();
      setSubmitted(true);
    } catch (err) {
      setSubmitError(
        `Could not create your order: ${(err as Error).message}\n\nPlease contact us directly to complete your purchase.`
      );
    } finally {
      setSubmitting(false);
    }
  };

  // ─── Empty cart ───────────────────────────────────────────────────────────
  if (items.length === 0 && !submitted) {
    return (
      <div className="min-h-screen bg-white">
        <div className="fixed top-0 left-0 right-0 z-50"><Navbar /></div>
        <div className="flex flex-col items-center justify-center min-h-screen gap-6" style={{ paddingTop: 64 }}>
          <div className="w-16 h-16 flex items-center justify-center" style={{ background: "#f5f4f2" }}>
            <i className="ri-shopping-cart-line text-2xl text-[#bbb]"></i>
          </div>
          <p className="font-black uppercase tracking-widest text-sm text-[#999]">Your cart is empty</p>
          <Link to="/shop" className="font-black uppercase tracking-widest text-[11px] px-8 py-4 cursor-pointer whitespace-nowrap" style={{ background: "#111", color: "#fff" }}>
            Browse Products
          </Link>
        </div>
        <FooterSection />
      </div>
    );
  }

  // ─── Success screen ───────────────────────────────────────────────────────
  if (submitted) {
    return (
      <div className="min-h-screen bg-white">
        <div className="fixed top-0 left-0 right-0 z-50"><Navbar /></div>
        <div className="flex flex-col items-center justify-center min-h-screen gap-8 px-8" style={{ paddingTop: 64 }}>
          <div className="w-20 h-20 flex items-center justify-center" style={{ background: "#f0fdf4", border: "1px solid #bbf7d0" }}>
            <i className="ri-check-line text-3xl text-green-600"></i>
          </div>
          <div className="text-center max-w-md">
            <p className="text-[11px] font-bold uppercase tracking-[0.3em] text-[#aaa] mb-3">Order Received</p>
            <h1 className="font-black uppercase text-3xl text-[#111] mb-4 tracking-tight">Thank You!</h1>
            {orderId && (
              <p className="text-[#888] text-xs mb-2 uppercase tracking-widest font-bold">Order #{orderId}</p>
            )}
            <p className="text-[#666] text-sm leading-relaxed mb-2">
              Your order has been received. Please complete your payment using the details below.
            </p>
            <p className="text-[#888] text-xs leading-relaxed">
              Once payment is confirmed, we'll process and ship within 1–2 business days. A confirmation will be sent to <strong className="text-[#555]">{form.email}</strong>.
            </p>
          </div>

          {/* Payment reminder */}
          <div className="w-full max-w-md p-6" style={{ background: "#f8f7f5", border: "1px solid #e0e0e0" }}>
            <p className="text-[10px] font-black uppercase tracking-widest text-[#aaa] mb-4">Complete Your Payment</p>
            {method === "zelle" ? (
              <div className="space-y-3">
                <div className="flex items-center justify-between py-3" style={{ borderBottom: "1px solid #ebebeb" }}>
                  <span className="text-[#888] text-xs">Send to</span>
                  <span className="text-[#111] font-black text-sm">{ZELLE_INFO.phone}</span>
                </div>
                <div className="flex items-center justify-between py-3" style={{ borderBottom: "1px solid #ebebeb" }}>
                  <span className="text-[#888] text-xs">Recipient</span>
                  <span className="text-[#111] font-bold text-sm">{ZELLE_INFO.name}</span>
                </div>
                <div className="flex items-center justify-between py-3">
                  <span className="text-[#888] text-xs">Amount</span>
                  <span className="text-[#111] font-black text-xl">${totalPrice.toFixed(2)}</span>
                </div>
              </div>
            ) : method === "cashapp" ? (
              <div className="space-y-3">
                <div className="flex items-center justify-between py-3" style={{ borderBottom: "1px solid #ebebeb" }}>
                  <span className="text-[#888] text-xs">Send to</span>
                  <span className="text-[#111] font-black text-sm">{CASHAPP_INFO.tag}</span>
                </div>
                <div className="flex items-center justify-between py-3">
                  <span className="text-[#888] text-xs">Amount</span>
                  <span className="text-[#111] font-black text-xl">${totalPrice.toFixed(2)}</span>
                </div>
              </div>
            ) : (
              <div className="space-y-3">
                <div className="flex items-center justify-between py-3" style={{ borderBottom: "1px solid #ebebeb" }}>
                  <span className="text-[#888] text-xs">Send to</span>
                  <span className="text-[#111] font-black text-sm">{VENMO_INFO.tag}</span>
                </div>
                <div className="flex items-center justify-between py-3">
                  <span className="text-[#888] text-xs">Amount</span>
                  <span className="text-[#111] font-black text-xl">${totalPrice.toFixed(2)}</span>
                </div>
              </div>
            )}
            <p className="text-[#aaa] text-[10px] mt-4 leading-relaxed">
              Include your name and order #{orderId ?? "number"} in the payment note so we can match it.
            </p>
          </div>

          <Link to="/shop" className="font-black uppercase tracking-widest text-[11px] px-8 py-4 cursor-pointer whitespace-nowrap" style={{ background: "#111", color: "#fff" }}>
            Continue Shopping
          </Link>
        </div>
        <FooterSection />
      </div>
    );
  }

  // ─── Main checkout ────────────────────────────────────────────────────────
  return (
    <div className="min-h-screen" style={{ background: "#f8f7f5" }}>
      <div className="fixed top-0 left-0 right-0 z-50"><Navbar /></div>

      <div style={{ paddingTop: 64 }}>
        {/* Header */}
        <div className="w-full py-12 px-8" style={{ background: "#111111" }}>
          <div className="max-w-[1100px] mx-auto">
            <p className="text-[11px] font-bold uppercase tracking-[0.3em] text-white/40 mb-3">Valkyrie Peptides</p>
            <h1 className="font-black uppercase tracking-tight leading-none" style={{ fontSize: "clamp(28px, 4vw, 52px)", background: "linear-gradient(135deg, #888 0%, #c0c0c0 30%, #606060 55%, #aaa 75%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}>
              COMPLETE YOUR ORDER
            </h1>
          </div>
        </div>

        {/* Progress bar */}
        <div className="w-full bg-white" style={{ borderBottom: "1px solid #e8e8e8" }}>
          <div className="max-w-[1100px] mx-auto px-8 py-4 flex items-center gap-0">
            {[{ n: 1, label: "Shipping" }, { n: 2, label: "Payment" }, { n: 3, label: "Review" }].map((s, i) => (
              <div key={s.n} className="flex items-center">
                <div className="flex items-center gap-2">
                  <div className="w-7 h-7 flex items-center justify-center font-black text-xs" style={{ background: step >= s.n ? "#111" : "#e8e8e8", color: step >= s.n ? "#fff" : "#aaa" }}>
                    {step > s.n ? <i className="ri-check-line text-xs"></i> : s.n}
                  </div>
                  <span className="text-[10px] font-bold uppercase tracking-widest hidden sm:block" style={{ color: step >= s.n ? "#111" : "#bbb" }}>
                    {s.label}
                  </span>
                </div>
                {i < 2 && <div className="w-12 md:w-24 mx-3" style={{ height: 1, background: step > s.n ? "#111" : "#e0e0e0" }} />}
              </div>
            ))}
          </div>
        </div>

        {/* Body */}
        <div className="max-w-[1100px] mx-auto px-8 py-10 grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">

            {/* ── STEP 1: Shipping ── */}
            {step === 1 && (
              <div>
                <h2 className="font-black uppercase tracking-tight text-[#111] text-xl mb-8">Shipping Information</h2>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  {[
                    { name: "firstName", label: "First Name", half: true },
                    { name: "lastName",  label: "Last Name",  half: true },
                    { name: "email",     label: "Email Address", half: false },
                    { name: "phone",     label: "Phone Number",  half: false },
                    { name: "address",   label: "Street Address", half: false },
                    { name: "city",      label: "City",   half: true },
                    { name: "state",     label: "State",  half: true },
                    { name: "zip",       label: "ZIP Code", half: false },
                  ].map(({ name, label, half }) => (
                    <div key={name} className={half ? "" : "col-span-2"}>
                      <label className="block text-[10px] font-black uppercase tracking-widest text-[#888] mb-2">{label}</label>
                      <input
                        name={name}
                        value={(form as Record<string, string>)[name]}
                        onChange={handleChange}
                        required
                        className="w-full px-4 py-3 text-sm text-[#111] focus:outline-none transition-colors"
                        style={{ background: "#fff", border: "1px solid #e0e0e0" }}
                        onFocus={(e) => { e.target.style.border = "1px solid #111"; }}
                        onBlur={(e) => { e.target.style.border = "1px solid #e0e0e0"; }}
                      />
                    </div>
                  ))}
                </div>
                <button
                  onClick={() => { if (form.firstName && form.email && form.address) { setStep(2); window.scrollTo(0, 0); } }}
                  className="w-full font-black uppercase tracking-widest text-[11px] py-4 cursor-pointer whitespace-nowrap"
                  style={{ background: "#111", color: "#fff" }}
                >
                  Continue to Payment
                </button>
              </div>
            )}

            {/* ── STEP 2: Payment ── */}
            {step === 2 && (
              <div>
                <h2 className="font-black uppercase tracking-tight text-[#111] text-xl mb-8">Payment Method</h2>
                <p className="text-[#888] text-xs mb-6 leading-relaxed">
                  We accept Zelle, Cash App, and Venmo. Send payment after placing your order — include your name and email in the note.
                </p>

                <div className="space-y-3 mb-8">
                  {(["zelle", "cashapp", "venmo"] as PaymentMethod[]).map((m) => {
                    const info =
                      m === "zelle"   ? `${ZELLE_INFO.phone} · ${ZELLE_INFO.name}`
                      : m === "cashapp" ? CASHAPP_INFO.tag
                      :                   VENMO_INFO.tag;
                    return (
                      <label
                        key={m}
                        className="flex items-center gap-4 p-5 cursor-pointer transition-colors"
                        style={{ background: method === m ? "#fff" : "#fafafa", border: method === m ? "2px solid #111" : "1px solid #e0e0e0" }}
                      >
                        <input type="radio" name="payment" value={m} checked={method === m} onChange={() => setMethod(m)} className="sr-only" />
                        <div className="w-5 h-5 flex items-center justify-center flex-shrink-0" style={{ border: "2px solid", borderColor: method === m ? "#111" : "#ccc", borderRadius: "50%", background: method === m ? "#111" : "transparent" }}>
                          {method === m && <div className="w-2 h-2 bg-white rounded-full" />}
                        </div>
                        <div>
                          <p className="text-[#111] font-black text-sm uppercase tracking-wide">{METHOD_LABELS[m]}</p>
                          <p className="text-[#888] text-xs mt-0.5">{info}</p>
                        </div>
                      </label>
                    );
                  })}
                </div>

                {/* Payment instructions preview */}
                <div className="p-5 mb-8" style={{ background: "#f8f7f5", border: "1px solid #e8e8e8" }}>
                  <p className="text-[10px] font-black uppercase tracking-widest text-[#aaa] mb-3">After placing your order, send:</p>
                  <div className="flex items-center justify-between">
                    <span className="text-[#666] text-xs">
                      {method === "zelle" ? `Zelle → ${ZELLE_INFO.phone}` : method === "cashapp" ? `Cash App → ${CASHAPP_INFO.tag}` : `Venmo → ${VENMO_INFO.tag}`}
                    </span>
                    <span className="text-[#111] font-black">${totalPrice.toFixed(2)}</span>
                  </div>
                </div>

                <div className="flex gap-3">
                  <button onClick={() => { setStep(1); window.scrollTo(0, 0); }} className="px-6 py-4 font-black uppercase tracking-widest text-[11px] cursor-pointer whitespace-nowrap" style={{ background: "#fff", color: "#111", border: "1px solid #e0e0e0" }}>
                    Back
                  </button>
                  <button onClick={() => { setStep(3); window.scrollTo(0, 0); }} className="flex-1 font-black uppercase tracking-widest text-[11px] py-4 cursor-pointer whitespace-nowrap" style={{ background: "#111", color: "#fff" }}>
                    Review Order
                  </button>
                </div>
              </div>
            )}

            {/* ── STEP 3: Review & submit ── */}
            {step === 3 && (
              <form onSubmit={handleSubmitOrder}>
                <h2 className="font-black uppercase tracking-tight text-[#111] text-xl mb-8">Review &amp; Confirm</h2>

                {/* Shipping summary */}
                <div className="p-5 mb-4" style={{ background: "#fff", border: "1px solid #e0e0e0" }}>
                  <div className="flex items-center justify-between mb-4">
                    <p className="text-[10px] font-black uppercase tracking-widest text-[#aaa]">Shipping To</p>
                    <button type="button" onClick={() => { setStep(1); window.scrollTo(0, 0); }} className="text-[10px] font-bold uppercase tracking-widest text-[#555] hover:text-[#111] cursor-pointer">Edit</button>
                  </div>
                  <p className="text-[#111] font-bold text-sm">{form.firstName} {form.lastName}</p>
                  <p className="text-[#666] text-xs mt-1">{form.address}</p>
                  <p className="text-[#666] text-xs">{form.city}, {form.state} {form.zip}</p>
                  <p className="text-[#666] text-xs mt-1">{form.email} · {form.phone}</p>
                </div>

                {/* Payment summary */}
                <div className="p-5 mb-8" style={{ background: "#fff", border: "1px solid #e0e0e0" }}>
                  <div className="flex items-center justify-between mb-4">
                    <p className="text-[10px] font-black uppercase tracking-widest text-[#aaa]">Payment Method</p>
                    <button type="button" onClick={() => { setStep(2); window.scrollTo(0, 0); }} className="text-[10px] font-bold uppercase tracking-widest text-[#555] hover:text-[#111] cursor-pointer">Edit</button>
                  </div>
                  <p className="text-[#111] font-bold text-sm">{METHOD_LABELS[method]}</p>
                  <p className="text-[#888] text-xs">
                    {method === "zelle" ? `Send $${totalPrice.toFixed(2)} to ${ZELLE_INFO.phone}` : method === "cashapp" ? `Send $${totalPrice.toFixed(2)} to ${CASHAPP_INFO.tag}` : `Send $${totalPrice.toFixed(2)} to ${VENMO_INFO.tag}`}
                  </p>
                </div>

                {/* Order notes */}
                <div className="mb-8">
                  <label className="block text-[10px] font-black uppercase tracking-widest text-[#888] mb-2">Order Notes (Optional)</label>
                  <textarea
                    name="notes"
                    value={form.notes}
                    onChange={handleChange}
                    placeholder="Any special instructions for your order..."
                    rows={3}
                    maxLength={500}
                    className="w-full px-4 py-3 text-sm text-[#111] focus:outline-none transition-colors resize-none"
                    style={{ background: "#fff", border: "1px solid #e0e0e0" }}
                    onFocus={(e) => { (e.target as HTMLTextAreaElement).style.border = "1px solid #111"; }}
                    onBlur={(e) => { (e.target as HTMLTextAreaElement).style.border = "1px solid #e0e0e0"; }}
                  />
                </div>

                {/* Payment confirmation checkbox */}
                <div className="mb-6 p-5" style={{ background: paymentConfirmed ? "#f0fdf4" : "#fffbeb", border: paymentConfirmed ? "1px solid #bbf7d0" : "1px solid #fde68a" }}>
                  <label className="flex items-start gap-4 cursor-pointer select-none">
                    <input type="checkbox" checked={paymentConfirmed} onChange={(e) => setPaymentConfirmed(e.target.checked)} style={{ width: 18, height: 18, accentColor: "#111", cursor: "pointer", marginTop: 2, flexShrink: 0 }} />
                    <div>
                      <p className="text-[#111] font-black text-xs uppercase tracking-wide mb-1">I confirm I have sent payment</p>
                      <p className="text-[#555] text-[11px] leading-relaxed">
                        I have already sent <strong>${totalPrice.toFixed(2)}</strong> via{" "}
                        <strong>{method === "zelle" ? `Zelle to ${ZELLE_INFO.phone}` : method === "cashapp" ? `Cash App to ${CASHAPP_INFO.tag}` : `Venmo to ${VENMO_INFO.tag}`}</strong>{" "}
                        and included my name and email in the payment note.
                      </p>
                    </div>
                  </label>
                </div>

                {/* API error */}
                {submitError && (
                  <div className="mb-6 p-4" style={{ background: "#fff1f2", border: "1px solid #fecdd3" }}>
                    <p className="text-red-700 text-xs font-bold uppercase tracking-wide mb-1">Order Failed</p>
                    <p className="text-red-600 text-[11px] leading-relaxed whitespace-pre-wrap">{submitError}</p>
                  </div>
                )}

                <div className="flex gap-3">
                  <button type="button" onClick={() => { setStep(2); window.scrollTo(0, 0); }} className="px-6 py-4 font-black uppercase tracking-widest text-[11px] cursor-pointer whitespace-nowrap" style={{ background: "#fff", color: "#111", border: "1px solid #e0e0e0" }}>
                    Back
                  </button>
                  <button
                    type="submit"
                    disabled={!paymentConfirmed || submitting}
                    className="flex-1 font-black uppercase tracking-widest text-[11px] py-4 whitespace-nowrap transition-all duration-200 flex items-center justify-center gap-2"
                    style={{ background: paymentConfirmed && !submitting ? "#111" : "#ccc", color: "#fff", cursor: paymentConfirmed && !submitting ? "pointer" : "not-allowed" }}
                  >
                    {submitting ? (
                      <>
                        <span className="inline-block w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" />
                        Placing Order…
                      </>
                    ) : paymentConfirmed ? (
                      `Place Order — $${totalPrice.toFixed(2)}`
                    ) : (
                      "Send Payment First to Continue"
                    )}
                  </button>
                </div>
              </form>
            )}
          </div>

          {/* ── RIGHT: Order summary ── */}
          <div className="lg:col-span-1">
            <div className="sticky top-24">
              <div style={{ background: "#fff", border: "1px solid #e0e0e0" }}>
                <div className="px-6 py-5" style={{ borderBottom: "1px solid #e8e8e8" }}>
                  <p className="text-[10px] font-black uppercase tracking-widest text-[#aaa]">Order Summary</p>
                </div>
                <div className="px-6 py-4 divide-y" style={{ borderColor: "#f0f0f0" }}>
                  {items.map((item) => (
                    <div key={item.id} className="flex items-center gap-3 py-4">
                      <div className="w-14 h-14 flex-shrink-0" style={{ background: "#f5f4f2" }}>
                        <img src={item.image} alt={item.name} className="w-full h-full object-contain p-1" style={{ mixBlendMode: "multiply" }} />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-[#111] font-bold text-[11px] uppercase tracking-wide leading-snug truncate">{item.name}</p>
                        <p className="text-[#888] text-[10px] mt-1">Qty: {item.quantity}</p>
                      </div>
                      <p className="text-[#111] font-black text-sm flex-shrink-0">${(item.price * item.quantity).toFixed(2)}</p>
                    </div>
                  ))}
                </div>
                <div className="px-6 py-4" style={{ borderTop: "2px solid #f0f0f0" }}>
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-[#888] text-xs">Subtotal</span>
                    <span className="text-[#111] font-bold text-sm">${totalPrice.toFixed(2)}</span>
                  </div>
                  <div className="flex items-center justify-between mb-4">
                    <span className="text-[#888] text-xs">Shipping</span>
                    <span className="text-green-600 font-bold text-xs">Free</span>
                  </div>
                  <div className="flex items-center justify-between pt-3" style={{ borderTop: "1px solid #e8e8e8" }}>
                    <span className="text-[#111] font-black text-sm uppercase tracking-wide">Total</span>
                    <span className="text-[#111] font-black text-xl">${totalPrice.toFixed(2)}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <FooterSection />
    </div>
  );
}
