import { useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useCart } from "@/hooks/useCart";

export default function CartDrawer() {
  const { items, isOpen, closeCart, removeItem, updateQty, totalPrice, totalItems } = useCart();
  const navigate = useNavigate();

  // Lock body scroll when drawer is open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => { document.body.style.overflow = ""; };
  }, [isOpen]);

  return (
    <>
      {/* Backdrop */}
      <div
        className="fixed inset-0 z-[200] transition-opacity duration-300"
        style={{
          background: "rgba(0,0,0,0.45)",
          opacity: isOpen ? 1 : 0,
          pointerEvents: isOpen ? "auto" : "none",
        }}
        onClick={closeCart}
      />

      {/* Drawer */}
      <div
        className="fixed top-0 right-0 h-full z-[201] flex flex-col"
        style={{
          width: "min(420px, 100vw)",
          background: "#ffffff",
          transform: isOpen ? "translateX(0)" : "translateX(100%)",
          transition: "transform 0.35s cubic-bezier(0.4,0,0.2,1)",
          borderLeft: "1px solid #e0e0e0",
        }}
      >
        {/* Header */}
        <div
          className="flex items-center justify-between px-7 py-5 flex-shrink-0"
          style={{ borderBottom: "1px solid #e8e8e8" }}
        >
          <div className="flex items-center gap-3">
            <h2 className="font-black uppercase tracking-widest text-[13px] text-[#111]">Cart</h2>
            {totalItems > 0 && (
              <span
                className="text-[10px] font-black text-white px-2 py-0.5 rounded-full"
                style={{ background: "#111" }}
              >
                {totalItems}
              </span>
            )}
          </div>
          <button
            onClick={closeCart}
            className="w-8 h-8 flex items-center justify-center text-[#555] hover:text-[#111] transition-colors cursor-pointer"
          >
            <i className="ri-close-line text-xl"></i>
          </button>
        </div>

        {/* Items */}
        <div className="flex-1 overflow-y-auto px-7 py-4">
          {items.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full gap-4 text-center">
              <div className="w-16 h-16 flex items-center justify-center" style={{ background: "#f5f4f2" }}>
                <i className="ri-shopping-cart-line text-2xl text-[#bbb]"></i>
              </div>
              <p className="font-black uppercase tracking-widest text-xs text-[#999]">Your cart is empty</p>
              <p className="text-[#bbb] text-xs leading-relaxed max-w-[200px]">
                Add some research peptides to get started.
              </p>
              <button
                onClick={closeCart}
                className="mt-2 font-black uppercase tracking-widest text-[11px] px-6 py-3 cursor-pointer whitespace-nowrap"
                style={{ background: "#111", color: "#fff" }}
              >
                Continue Shopping
              </button>
            </div>
          ) : (
            <div className="flex flex-col gap-0" style={{ borderTop: "1px solid #ebebeb" }}>
              {items.map((item) => (
                <div
                  key={item.id}
                  className="flex items-start gap-4 py-5"
                  style={{ borderBottom: "1px solid #ebebeb" }}
                >
                  {/* Product image */}
                  <Link
                    to={`/products/${item.slug}`}
                    onClick={closeCart}
                    className="flex-shrink-0 flex items-center justify-center cursor-pointer"
                    style={{ width: 72, height: 72, background: "#f0ede8", border: "1px solid #e8e8e8" }}
                  >
                    <img
                      src={item.image}
                      alt={item.name}
                      className="w-full h-full object-contain p-2"
                      style={{ mixBlendMode: "multiply" }}
                    />
                  </Link>

                  {/* Info */}
                  <div className="flex-1 min-w-0">
                    <Link
                      to={`/products/${item.slug}`}
                      onClick={closeCart}
                      className="block cursor-pointer"
                    >
                      <p className="text-[#aaa] text-[9px] uppercase tracking-widest mb-1">Research Grade</p>
                      <p className="text-[#111] font-black text-xs uppercase tracking-tight leading-snug mb-3 hover:text-[#555] transition-colors">
                        {item.name}
                      </p>
                    </Link>

                    {/* Qty + price row */}
                    <div className="flex items-center justify-between gap-3">
                      {/* Quantity stepper */}
                      <div
                        className="flex items-stretch"
                        style={{ border: "1px solid #e0e0e0" }}
                      >
                        <button
                          onClick={() => updateQty(item.id, item.quantity - 1)}
                          className="w-8 h-7 flex items-center justify-center text-[#555] hover:bg-[#f5f5f5] transition-colors cursor-pointer font-bold text-sm"
                        >
                          −
                        </button>
                        <div
                          className="w-8 h-7 flex items-center justify-center text-[#111] font-bold text-xs border-x"
                          style={{ borderColor: "#e0e0e0" }}
                        >
                          {item.quantity}
                        </div>
                        <button
                          onClick={() => updateQty(item.id, item.quantity + 1)}
                          className="w-8 h-7 flex items-center justify-center text-[#555] hover:bg-[#f5f5f5] transition-colors cursor-pointer font-bold text-sm"
                        >
                          +
                        </button>
                      </div>

                      <span className="font-black text-sm text-[#111]">
                        ${(item.price * item.quantity).toFixed(2)}
                      </span>
                    </div>
                  </div>

                  {/* Remove */}
                  <button
                    onClick={() => removeItem(item.id)}
                    className="w-6 h-6 flex items-center justify-center text-[#bbb] hover:text-[#dc2626] transition-colors cursor-pointer flex-shrink-0 mt-0.5"
                  >
                    <i className="ri-delete-bin-line text-sm"></i>
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        {items.length > 0 && (
          <div
            className="flex-shrink-0 px-7 py-6"
            style={{ borderTop: "1px solid #e8e8e8", background: "#fafafa" }}
          >
            {/* Subtotal */}
            <div className="flex items-center justify-between mb-2">
              <span className="text-[#888] text-xs font-semibold uppercase tracking-widest">Subtotal</span>
              <span className="text-[#111] font-black text-lg">${totalPrice.toFixed(2)}</span>
            </div>
            <p className="text-[#bbb] text-[10px] mb-5">Shipping calculated at checkout.</p>

            {/* Checkout CTA */}
            <button
              onClick={() => { closeCart(); navigate("/order"); }}
              className="w-full font-black uppercase tracking-widest text-[11px] py-4 cursor-pointer whitespace-nowrap transition-all duration-200 flex items-center justify-center gap-2"
              style={{ background: "#111111", color: "#ffffff" }}
              onMouseEnter={(e) => { (e.currentTarget as HTMLButtonElement).style.background = "#333"; }}
              onMouseLeave={(e) => { (e.currentTarget as HTMLButtonElement).style.background = "#111111"; }}
            >
              <div className="w-4 h-4 flex items-center justify-center">
                <i className="ri-arrow-right-line text-xs"></i>
              </div>
              Proceed to Order
            </button>

            {/* Continue shopping */}
            <button
              onClick={closeCart}
              className="w-full mt-3 font-bold uppercase tracking-widest text-[11px] py-3 cursor-pointer whitespace-nowrap text-[#555] hover:text-[#111] transition-colors"
            >
              Continue Shopping
            </button>

            {/* Payment methods */}
            <div className="mt-4 pt-4" style={{ borderTop: "1px solid #ebebeb" }}>
              <p className="text-[#bbb] text-[10px] font-bold uppercase tracking-widest mb-3 text-center">We Accept</p>
              <div className="flex flex-wrap items-center justify-center gap-3">
                <img
                  src="https://public.readdy.ai/ai/img_res/b8d01e3a-d9d3-4846-aa11-8461b6dfa380.png"
                  alt="Zelle"
                  className="h-10 w-auto object-contain"
                />
                <img
                  src="https://public.readdy.ai/ai/img_res/cfa1dc1c-5a79-4020-a687-aa6ee9dcb1c8.png"
                  alt="Cash App"
                  className="h-12 w-auto object-contain"
                />
                <img
                  src="https://public.readdy.ai/ai/img_res/800f4520-4a80-46c9-80f4-61892e19dab0.png"
                  alt="Venmo"
                  className="h-12 w-auto object-contain"
                />
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
}
