import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import Navbar from "@/components/feature/Navbar";
import FooterSection from "@/pages/home/components/FooterSection";

export default function ContactPage() {
  useEffect(() => { window.scrollTo(0, 0); }, []);

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone: "",
    subject: "",
    message: "",
  });
  const [submitted, setSubmitted] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!formData.name || !formData.email || !formData.message) {
      setError("Please fill in all required fields.");
      return;
    }
    if (formData.message.length > 500) {
      setError("Message cannot exceed 500 characters.");
      return;
    }
    setError("");
    setSubmitting(true);
    try {
      const params = new URLSearchParams();
      params.append("name", formData.name);
      params.append("email", formData.email);
      params.append("phone", formData.phone);
      params.append("subject", formData.subject);
      params.append("message", formData.message);

      const res = await fetch("https://readdy.ai/api/form/d7kapei63r16okiqpg90", {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: params.toString(),
      });
      if (res.ok) {
        setSubmitted(true);
      } else {
        setError("Something went wrong. Please try again.");
      }
    } catch {
      setError("Something went wrong. Please try again.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen" style={{ background: "#f8f7f5" }}>
      <div className="fixed top-0 left-0 right-0 z-50">
        <Navbar />
      </div>

      <div style={{ paddingTop: 64 }}>
        {/* Page header — product photo background */}
        <div className="relative overflow-hidden py-20 px-8" style={{ minHeight: 280 }}>
          <img
            src="/IMG_0912.jpeg"
            alt=""
            className="absolute inset-0 w-full h-full object-cover"
            style={{ objectPosition: "center 45%", filter: "brightness(0.35) contrast(1.1)" }}
          />
          <div className="absolute inset-0" style={{ background: "linear-gradient(to right, rgba(5,5,5,0.85) 0%, rgba(5,5,5,0.5) 55%, rgba(5,5,5,0.65) 100%)" }} />
          <div className="absolute" style={{ top: 16, left: 16, width: 20, height: 20, borderTop: "1.5px solid rgba(192,192,192,0.5)", borderLeft: "1.5px solid rgba(192,192,192,0.5)" }} />
          <div className="absolute" style={{ top: 16, right: 16, width: 20, height: 20, borderTop: "1.5px solid rgba(192,192,192,0.5)", borderRight: "1.5px solid rgba(192,192,192,0.5)" }} />
          <div className="absolute" style={{ bottom: 16, left: 16, width: 20, height: 20, borderBottom: "1.5px solid rgba(192,192,192,0.5)", borderLeft: "1.5px solid rgba(192,192,192,0.5)" }} />
          <div className="absolute" style={{ bottom: 16, right: 16, width: 20, height: 20, borderBottom: "1.5px solid rgba(192,192,192,0.5)", borderRight: "1.5px solid rgba(192,192,192,0.5)" }} />
          <div className="relative z-10 max-w-[1320px] mx-auto">
            <p className="text-[11px] font-bold uppercase tracking-[0.3em] mb-4" style={{ color: "rgba(192,192,192,0.55)", fontFamily: "'Share Tech Mono', monospace" }}>Support</p>
            <h1 className="font-black uppercase leading-[0.88] tracking-tight" style={{ fontSize: "clamp(36px, 5vw, 72px)", background: "linear-gradient(135deg, #888 0%, #c0c0c0 30%, #606060 55%, #aaa 75%, #777 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}>
              CONTACT<br />
              <span style={{ background: "linear-gradient(135deg, #707070 0%, #b0b0b0 30%, #484848 55%, #999 75%, #606060 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text", fontFamily: "'Oswald', sans-serif", fontWeight: 700 }}>US</span>
            </h1>
            <p className="text-sm mt-5 max-w-lg leading-relaxed" style={{ color: "rgba(255,255,255,0.5)" }}>
              Questions about products, orders, or research applications? Our team is available 7 days a week to help.
            </p>
          </div>
        </div>

        {/* Breadcrumb */}
        <div style={{ background: "#ffffff", borderBottom: "1px solid #e8e8e8" }} className="px-8 py-3">
          <div className="max-w-[1320px] mx-auto flex items-center gap-2 text-xs text-[#aaa]">
            <Link to="/" className="hover:text-[#111] transition-colors cursor-pointer">Home</Link>
            <i className="ri-arrow-right-s-line"></i>
            <span className="text-[#111]">Contact Us</span>
          </div>
        </div>

        {/* Main content */}
        <div className="py-16 px-8">
          <div className="max-w-[1320px] mx-auto">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-px" style={{ background: "#e0e0e0" }}>

              {/* Left sidebar - contact info */}
              <div className="bg-white p-10 flex flex-col gap-10">
                <div>
                  <p className="text-[11px] font-bold uppercase tracking-[0.3em] text-[#aaa] mb-6">Get In Touch</p>

                  {/* Phone */}
                  <div className="flex gap-4 items-start mb-8">
                    <div className="w-10 h-10 flex items-center justify-center flex-shrink-0" style={{ background: "#111" }}>
                      <i className="ri-phone-line text-white text-base"></i>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold uppercase tracking-widest text-[#aaa] mb-1">Phone</p>
                      <a href="tel:2082439222" className="text-[#111] font-bold text-base hover:text-[#555] transition-colors cursor-pointer">(208) 243-9222</a>
                      <p className="text-[#aaa] text-xs mt-1">7 days a week support</p>
                    </div>
                  </div>

                  {/* Email */}
                  <div className="flex gap-4 items-start mb-8">
                    <div className="w-10 h-10 flex items-center justify-center flex-shrink-0" style={{ background: "#111" }}>
                      <i className="ri-mail-line text-white text-base"></i>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold uppercase tracking-widest text-[#aaa] mb-1">Email</p>
                      <a href="mailto:support@valkyriepeptides.com" className="text-[#111] font-bold text-sm hover:text-[#555] transition-colors cursor-pointer">support@valkyriepeptides.com</a>
                      <p className="text-[#aaa] text-xs mt-1">We reply within 24 hours</p>
                    </div>
                  </div>

                  {/* Location */}
                  <div className="flex gap-4 items-start mb-8">
                    <div className="w-10 h-10 flex items-center justify-center flex-shrink-0" style={{ background: "#111" }}>
                      <i className="ri-map-pin-line text-white text-base"></i>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold uppercase tracking-widest text-[#aaa] mb-1">Location</p>
                      <p className="text-[#111] font-bold text-sm">Boise, Idaho</p>
                      <p className="text-[#aaa] text-xs mt-1">United States</p>
                    </div>
                  </div>

                  {/* Hours */}
                  <div className="flex gap-4 items-start">
                    <div className="w-10 h-10 flex items-center justify-center flex-shrink-0" style={{ background: "#111" }}>
                      <i className="ri-time-line text-white text-base"></i>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold uppercase tracking-widest text-[#aaa] mb-1">Support Hours</p>
                      <p className="text-[#111] font-bold text-sm">Mon – Sun</p>
                      <p className="text-[#aaa] text-xs mt-1">9:00 AM – 6:00 PM MST</p>
                    </div>
                  </div>
                </div>

                {/* Military / Vets promo */}
                <div className="p-6" style={{ background: "#111" }}>
                  <p className="text-[10px] font-black uppercase tracking-widest text-white/40 mb-2">Special Discount</p>
                  <p className="text-white font-black text-lg leading-snug mb-2">20% Off for Life</p>
                  <p className="text-white/55 text-xs leading-relaxed">
                    Active Military, Veterans &amp; First Responders receive a permanent 20% discount. Contact us to receive your personal code.
                  </p>
                </div>

                {/* Quick links */}
                <div>
                  <p className="text-[10px] font-bold uppercase tracking-widest text-[#aaa] mb-4">Quick Links</p>
                  <div className="space-y-2">
                    {[
                      { label: "View All Products", to: "/shop" },
                      { label: "FAQs", to: "/faq" },
                      { label: "Certificates of Analysis", to: "/coa" },
                      { label: "Return Policy", to: "/return-policy" },
                    ].map((link) => (
                      <Link key={link.label} to={link.to} className="flex items-center justify-between py-2.5 group cursor-pointer" style={{ borderBottom: "1px solid #f0f0f0" }}>
                        <span className="text-[#555] text-sm font-semibold group-hover:text-[#111] transition-colors">{link.label}</span>
                        <div className="w-4 h-4 flex items-center justify-center">
                          <i className="ri-arrow-right-line text-[#ccc] text-sm group-hover:text-[#111] transition-colors"></i>
                        </div>
                      </Link>
                    ))}
                  </div>
                </div>
              </div>

              {/* Right: form (spans 2 cols) */}
              <div className="lg:col-span-2 bg-white p-10">
                {submitted ? (
                  <div className="flex flex-col items-center justify-center h-full min-h-[500px] text-center">
                    <div className="w-16 h-16 flex items-center justify-center mb-6" style={{ background: "#111" }}>
                      <i className="ri-check-line text-white text-2xl"></i>
                    </div>
                    <h2 className="font-black text-2xl uppercase tracking-tight text-[#111] mb-3">Message Sent!</h2>
                    <p className="text-[#777] text-sm max-w-sm leading-relaxed mb-8">
                      Thank you for reaching out. Our team will get back to you within 24 hours.
                    </p>
                    <button
                      onClick={() => { setSubmitted(false); setFormData({ name: "", email: "", phone: "", subject: "", message: "" }); }}
                      className="font-black uppercase tracking-widest text-xs px-8 py-4 cursor-pointer whitespace-nowrap"
                      style={{ background: "#111", color: "#fff" }}
                    >
                      Send Another Message
                    </button>
                  </div>
                ) : (
                  <>
                    <div className="mb-8">
                      <p className="text-[11px] font-bold uppercase tracking-[0.3em] text-[#aaa] mb-3">Send a Message</p>
                      <h2 className="font-black text-2xl uppercase tracking-tight text-[#111]">How Can We Help?</h2>
                    </div>

                    <form
                      id="contact-form"
                      data-readdy-form
                      onSubmit={handleSubmit}
                      className="space-y-5"
                    >
                      {/* Name + Email */}
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                        <div>
                          <label className="block text-[10px] font-bold uppercase tracking-widest text-[#888] mb-2">
                            Full Name <span className="text-red-500">*</span>
                          </label>
                          <input
                            type="text"
                            name="name"
                            value={formData.name}
                            onChange={handleChange}
                            placeholder="Dr. John Smith"
                            className="w-full px-4 py-3 text-sm text-[#111] outline-none transition-colors"
                            style={{ border: "1px solid #e0e0e0", background: "#fafafa" }}
                            onFocus={(e) => { e.currentTarget.style.borderColor = "#111"; e.currentTarget.style.background = "#fff"; }}
                            onBlur={(e) => { e.currentTarget.style.borderColor = "#e0e0e0"; e.currentTarget.style.background = "#fafafa"; }}
                          />
                        </div>
                        <div>
                          <label className="block text-[10px] font-bold uppercase tracking-widest text-[#888] mb-2">
                            Email Address <span className="text-red-500">*</span>
                          </label>
                          <input
                            type="email"
                            name="email"
                            value={formData.email}
                            onChange={handleChange}
                            placeholder="john@laboratory.com"
                            className="w-full px-4 py-3 text-sm text-[#111] outline-none transition-colors"
                            style={{ border: "1px solid #e0e0e0", background: "#fafafa" }}
                            onFocus={(e) => { e.currentTarget.style.borderColor = "#111"; e.currentTarget.style.background = "#fff"; }}
                            onBlur={(e) => { e.currentTarget.style.borderColor = "#e0e0e0"; e.currentTarget.style.background = "#fafafa"; }}
                          />
                        </div>
                      </div>

                      {/* Phone + Subject */}
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
                        <div>
                          <label className="block text-[10px] font-bold uppercase tracking-widest text-[#888] mb-2">Phone Number</label>
                          <input
                            type="tel"
                            name="phone"
                            value={formData.phone}
                            onChange={handleChange}
                            placeholder="(208) 000-0000"
                            className="w-full px-4 py-3 text-sm text-[#111] outline-none transition-colors"
                            style={{ border: "1px solid #e0e0e0", background: "#fafafa" }}
                            onFocus={(e) => { e.currentTarget.style.borderColor = "#111"; e.currentTarget.style.background = "#fff"; }}
                            onBlur={(e) => { e.currentTarget.style.borderColor = "#e0e0e0"; e.currentTarget.style.background = "#fafafa"; }}
                          />
                        </div>
                        <div>
                          <label className="block text-[10px] font-bold uppercase tracking-widest text-[#888] mb-2">Subject</label>
                          <select
                            name="subject"
                            value={formData.subject}
                            onChange={handleChange}
                            className="w-full px-4 py-3 text-sm text-[#111] outline-none transition-colors cursor-pointer appearance-none"
                            style={{ border: "1px solid #e0e0e0", background: "#fafafa" }}
                          >
                            <option value="">Select a topic...</option>
                            <option value="Order Inquiry">Order Inquiry</option>
                            <option value="Product Question">Product Question</option>
                            <option value="Shipping &amp; Tracking">Shipping &amp; Tracking</option>
                            <option value="Return / Refund">Return / Refund</option>
                            <option value="Military / Vet Discount">Military / Vet Discount</option>
                            <option value="Bulk Pricing">Bulk Pricing</option>
                            <option value="COA Request">COA Request</option>
                            <option value="Other">Other</option>
                          </select>
                        </div>
                      </div>

                      {/* Message */}
                      <div>
                        <label className="block text-[10px] font-bold uppercase tracking-widest text-[#888] mb-2">
                          Message <span className="text-red-500">*</span>
                          <span className="ml-2 font-normal normal-case tracking-normal text-[#ccc]">({formData.message.length}/500)</span>
                        </label>
                        <textarea
                          name="message"
                          value={formData.message}
                          onChange={handleChange}
                          maxLength={500}
                          rows={6}
                          placeholder="Tell us how we can help you..."
                          className="w-full px-4 py-3 text-sm text-[#111] outline-none transition-colors resize-none"
                          style={{ border: "1px solid #e0e0e0", background: "#fafafa" }}
                          onFocus={(e) => { e.currentTarget.style.borderColor = "#111"; e.currentTarget.style.background = "#fff"; }}
                          onBlur={(e) => { e.currentTarget.style.borderColor = "#e0e0e0"; e.currentTarget.style.background = "#fafafa"; }}
                        />
                      </div>

                      {/* Research use disclaimer checkbox */}
                      <div className="p-4" style={{ background: "#f8f7f5", border: "1px solid #e0e0e0" }}>
                        <p className="text-[#999] text-[10px] leading-relaxed uppercase tracking-wide">
                          By submitting this form you confirm you are 18+ and that any product inquiries relate to legitimate research use only. Not for human consumption.
                        </p>
                      </div>

                      {error && (
                        <p className="text-red-600 text-xs font-semibold">{error}</p>
                      )}

                      <button
                        type="submit"
                        disabled={submitting}
                        className="w-full font-black uppercase tracking-widest text-sm py-4 transition-all duration-200 cursor-pointer whitespace-nowrap disabled:opacity-60"
                        style={{ background: "#111111", color: "#ffffff" }}
                        onMouseEnter={(e) => { if (!submitting) (e.currentTarget as HTMLButtonElement).style.background = "#333"; }}
                        onMouseLeave={(e) => { if (!submitting) (e.currentTarget as HTMLButtonElement).style.background = "#111"; }}
                      >
                        {submitting ? "Sending..." : "Send Message"}
                      </button>
                    </form>
                  </>
                )}
              </div>
            </div>
          </div>
        </div>

        <FooterSection />
      </div>
    </div>
  );
}
