import { useState } from "react";

export default function AgeVerification() {
  const [dismissed, setDismissed] = useState(() => {
    try {
      return sessionStorage.getItem("age_verified") === "true";
    } catch {
      return false;
    }
  });

  const handleAccept = () => {
    try {
      sessionStorage.setItem("age_verified", "true");
    } catch {
      // ignore
    }
    setDismissed(true);
  };

  if (dismissed) return null;

  return (
    <div
      className="fixed inset-0 z-[200] flex items-center justify-center px-4"
      style={{ background: "rgba(0,0,0,0.75)", backdropFilter: "blur(4px)" }}
    >
      <div
        className="w-full max-w-[520px] flex flex-col items-center text-center rounded-2xl px-10 py-12"
        style={{
          background: "#1a1a1a",
          border: "1px solid rgba(255,255,255,0.1)",
        }}
      >
        {/* Logo */}
        <img
          src="https://valkyriepeptides.com/wp-content/uploads/2024/09/Valkyrie-Horizontal-2-1.webp"
          alt="Valkyrie Peptides"
          className="h-11 w-auto object-contain mb-8"
        />

        {/* Headline */}
        <h2
          className="font-black uppercase tracking-widest mb-4"
          style={{ fontSize: 18, color: "#ffffff", letterSpacing: "0.12em" }}
        >
          YOU MUST BE AT LEAST 18+ TO VISIT THIS SITE.
        </h2>

        {/* Subtext */}
        <p className="text-white/55 text-sm mb-7">
          By entering this site, you are accepting our Terms &amp; Conditions.
        </p>

        {/* CTA */}
        <button
          onClick={handleAccept}
          className="w-full font-bold py-4 rounded-lg text-sm uppercase tracking-widest transition-all duration-200 cursor-pointer whitespace-nowrap mb-6"
          style={{
            background: "rgba(255,255,255,0.08)",
            color: "#ffffff",
            border: "1px solid rgba(255,255,255,0.25)",
          }}
          onMouseEnter={(e) => {
            (e.currentTarget as HTMLButtonElement).style.background = "rgba(255,255,255,0.15)";
          }}
          onMouseLeave={(e) => {
            (e.currentTarget as HTMLButtonElement).style.background = "rgba(255,255,255,0.08)";
          }}
        >
          I Understand
        </button>

        {/* Disclaimer */}
        <p className="text-white/30 text-xs leading-relaxed">
          By using this site, you acknowledge that all products and information are provided for{" "}
          <strong className="text-white/50">research purposes only</strong> and are not intended for
          human consumption or medical use.
        </p>
      </div>
    </div>
  );
}
